from enum import Enum
from plum import dispatch
from typing import TypeVar, Union, Generic, List, Tuple
from spire.pdf.common import *
from spire.pdf import *
from ctypes import *
import abc

class PdfCollection(IEnumerable):
    """
    Base collection of the pdf objects.
    """

    @property
    def Count(self) -> int:
        """
        Gets number of the elements in the collection.
        Returns: The total number of elements in the collection.
        """
        GetDllLibPdf().spr_pdf_PdfCollection_get_Count.argtypes = [c_void_p]
        GetDllLibPdf().spr_pdf_PdfCollection_get_Count.restype = c_int
        ret = CallCFunction(GetDllLibPdf().spr_pdf_PdfCollection_get_Count,self.Ptr)
        return ret

    @property
    def List(self) -> 'IList':
        """
        Gets internal list of the collection.
        Returns: The internal list of the collection.
        """
        GetDllLibPdf().spr_pdf_PdfCollection_get_List.argtypes = [c_void_p]
        GetDllLibPdf().spr_pdf_PdfCollection_get_List.restype = c_void_p
        intPtr = CallCFunction(GetDllLibPdf().spr_pdf_PdfCollection_get_List,self.Ptr)
        ret = None if intPtr == None else IList(intPtr)
        return ret

    def GetEnumerator(self) -> 'IEnumerator':
        """
        Returns an enumerator that iterates through a collection.
        Returns: An enumerator that iterates through a collection.
        """
        GetDllLibPdf().spr_pdf_PdfCollection_GetEnumerator.argtypes = [c_void_p]
        GetDllLibPdf().spr_pdf_PdfCollection_GetEnumerator.restype = c_void_p
        intPtr = CallCFunction(GetDllLibPdf().spr_pdf_PdfCollection_GetEnumerator,self.Ptr)
        ret = None if intPtr == None else IEnumerator(intPtr)
        return ret